import { InView } from 'react-intersection-observer';
import styled, { keyframes } from "styled-components"
import SectionHeader from './SectionHeader'

import img from '../../img/ContactForm/bg-resized.jpg'

const Projects = ({ id }) => {
  return (
    <ProjectsContainer id={id}>
      <InView triggerOnce>
        {({ inView, ref, entry }) => (
          <SectionHeader inView={inView} ref={ref} />
        )}
      </InView>
      <InView triggerOnce>
        {({ inView, ref, entry }) => (
          <ProjectsList ref={ref}>
            {inView &&
              <>
                <Project>
                  <h4> Vans Scrapper Website </h4>
                  <ul>
                    <li> React </li>
                    <li> React Redux </li>
                    <li> Express </li>
                    <li> Mongoose </li>
                    <li> Puppeteer </li>
                    <li> Styled Components </li>
                  </ul>
                  <span> App that scrap data from Vans page every 24 hours
                    so they can be displayed with filtering and favourites afterwards, 
                    which is not possible on the official page. Purpose of creating such project
                    was to create a page that will be more enjoyable to use than the predecessor.
                  </span>
                  <ProjectLinks>
                    <li> Live Preview </li>
                    <li> Github </li>
                  </ProjectLinks>
                </Project>
                <Project>
                  <h4> Nekiro.dev </h4>
                  <ul>
                    <li> PHP Laravel </li>
                  </ul>
                  <span> desc </span>
                </Project>
              </>
            }
          </ProjectsList>
        )}
      </InView>

    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  /* height: 100vh; */
  padding: 3em 0 5em 0;
  color: white;
  /* font-size: 3em; */
`

const ProjectsList = styled.ul`
  margin-top: 3em;
  padding-left: 5em;
  display: grid;
  grid-template-columns: auto;
  width: 100%;
  padding-left: 15em;
  /* row-gap: 5em; */
  width: fit-content;
`

const fadeIn = keyframes`
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
`

const Project = styled.li`
  position: relative;
  display: flex;
  flex-direction: column;
  row-gap: 1em;
  padding: 1em;
  transition: 0.5s;
  border-radius: 4px;
  
  opacity: 0;
  animation: ${fadeIn} 1s forwards;
  animation-delay: 1.5s;

  &:hover {
    background: #242424;
  }

  & h4 {
    margin: 0;
    font-size: 3em;
  }
  
  & ul {
    padding: 0;
    display: flex;
    column-gap: 2em;
    letter-spacing: 1px;
    margin-bottom: 1em;
    text-transform: uppercase;
    font-size: 0.8em;
  }

  & span {
    max-width: 65ch;
    line-height: 2em;
    font-weight: 100;
  }
`

const ProjectLinks = styled.ul`
  margin-top: 1em;
  /* justify-content: flex-end; */

  & li {
    color: black;
    font-size: 1.5em;
    cursor: pointer;
    background: white;
    border-radius: 9px;
    padding: 1em;
  }
`



export default Projects
